<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Personal Expense Tracker</title>
  <style>
    * { box-sizing: border-box; }
    body { font-family: system-ui, sans-serif; max-width: 700px; margin: 2rem auto; padding: 0 1rem; line-height: 1.5; }
    h1 { margin-bottom: 1.5rem; }
    .form-row { display: flex; gap: 0.5rem; flex-wrap: wrap; margin-bottom: 0.75rem; align-items: center; }
    label { font-weight: 600; min-width: 80px; }
    input, select { padding: 0.5rem; border: 1px solid #ccc; border-radius: 4px; font-size: 1rem; }
    input[type="number"] { width: 100px; }
    input[type="date"] { width: 170px; }
    input[type="text"] { flex: 1; min-width: 200px; }
    select { min-width: 150px; }
    button { padding: 0.5rem 1rem; background: #2563eb; color: white; border: none; border-radius: 4px; cursor: pointer; font-size: 1rem; }
    button:hover { background: #1d4ed8; }
    #form-error { color: #dc2626; min-height: 1.25rem; margin-bottom: 1rem; }
    table { width: 100%; border-collapse: collapse; margin-top: 1.5rem; }
    th, td { padding: 0.75rem; text-align: left; border-bottom: 1px solid #e5e7eb; }
    th { background: #f9fafb; font-weight: 600; }
    .expense td { vertical-align: middle; }
    .exp-del { background: #dc2626; padding: 0.25rem 0.5rem; font-size: 0.875rem; }
    .exp-del:hover { background: #b91c1c; }
    .summary { margin-top: 1.5rem; padding: 1rem; background: #f9fafb; border-radius: 4px; }
    .summary-row { display: flex; justify-content: space-between; margin: 0.25rem 0; }
    .summary-row.total { font-weight: 700; font-size: 1.125rem; border-top: 1px solid #e5e7eb; padding-top: 0.5rem; margin-top: 0.5rem; }
    .filters { display: flex; gap: 1rem; flex-wrap: wrap; margin-bottom: 1rem; padding: 1rem; background: #f9fafb; border-radius: 4px; }
    .filter-group { display: flex; align-items: center; gap: 0.5rem; }
    .amount { text-align: right; font-variant-numeric: tabular-nums; }
    .category-badge { display: inline-block; padding: 0.125rem 0.5rem; border-radius: 9999px; font-size: 0.75rem; font-weight: 600; text-transform: capitalize; }
    .cat-groceries { background: #dcfce7; color: #166534; }
    .cat-transport { background: #dbeafe; color: #1e40af; }
    .cat-bills { background: #fef3c7; color: #92400e; }
    .cat-fun { background: #fce7f3; color: #9d174d; }
  </style>
</head>
<body>
  <h1>Personal Expense Tracker</h1>

  <form id="expense-form">
    <div class="form-row">
      <label for="amount">Amount</label>
      <input type="number" id="amount" step="0.01" min="0.01" placeholder="0.00" required>
    </div>
    <div class="form-row">
      <label for="category">Category</label>
      <select id="category" required>
        <option value="groceries">Groceries</option>
        <option value="transport">Transport</option>
        <option value="bills">Bills</option>
        <option value="fun">Fun</option>
      </select>
    </div>
    <div class="form-row">
      <label for="date">Date</label>
      <input type="date" id="date" required>
    </div>
    <div class="form-row">
      <label for="note">Note (optional)</label>
      <input type="text" id="note" placeholder="Optional description">
    </div>
    <div class="form-row">
      <button type="submit" id="add-expense">Add Expense</button>
    </div>
    <div id="form-error"></div>
  </form>

  <div class="filters">
    <div class="filter-group">
      <label for="filter-category">Category</label>
      <select id="filter-category">
        <option value="all">All</option>
        <option value="groceries">Groceries</option>
        <option value="transport">Transport</option>
        <option value="bills">Bills</option>
        <option value="fun">Fun</option>
      </select>
    </div>
    <div class="filter-group">
      <label for="filter-from">From</label>
      <input type="date" id="filter-from">
    </div>
    <div class="filter-group">
      <label for="filter-to">To</label>
      <input type="date" id="filter-to">
    </div>
  </div>

  <table>
    <thead>
      <tr>
        <th>Amount</th>
        <th>Category</th>
        <th>Date</th>
        <th>Note</th>
        <th></th>
      </tr>
    </thead>
    <tbody id="expense-list"></tbody>
  </table>

  <div class="summary">
    <div class="summary-row">
      <span>Groceries</span>
      <span class="cat-total" data-cat="groceries">0.00</span>
    </div>
    <div class="summary-row">
      <span>Transport</span>
      <span class="cat-total" data-cat="transport">0.00</span>
    </div>
    <div class="summary-row">
      <span>Bills</span>
      <span class="cat-total" data-cat="bills">0.00</span>
    </div>
    <div class="summary-row">
      <span>Fun</span>
      <span class="cat-total" data-cat="fun">0.00</span>
    </div>
    <div class="summary-row total">
      <span>Total</span>
      <span id="total">0.00</span>
    </div>
  </div>

  <script>
    const STORAGE_KEY = 'expenses';
    const CATEGORIES = ['groceries', 'transport', 'bills', 'fun'];

    let expenses = [];

    const amountEl = document.getElementById('amount');
    const categoryEl = document.getElementById('category');
    const dateEl = document.getElementById('date');
    const noteEl = document.getElementById('note');
    const formErrorEl = document.getElementById('form-error');
    const expenseListEl = document.getElementById('expense-list');
    const totalEl = document.getElementById('total');
    const filterCategoryEl = document.getElementById('filter-category');
    const filterFromEl = document.getElementById('filter-from');
    const filterToEl = document.getElementById('filter-to');

    function loadExpenses() {
      try {
        const stored = localStorage.getItem(STORAGE_KEY);
        if (stored) {
          expenses = JSON.parse(stored);
        }
      } catch (e) {
        expenses = [];
      }
    }

    function saveExpenses() {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
    }

    function formatCurrency(value) {
      return value.toFixed(2);
    }

    function createCategoryBadge(category) {
      const span = document.createElement('span');
      span.className = `category-badge cat-${category}`;
      span.textContent = category;
      return span;
    }

    function matchesFilters(expense) {
      const catFilter = filterCategoryEl.value;
      if (catFilter !== 'all' && expense.category !== catFilter) return false;

      const from = filterFromEl.value;
      const to = filterToEl.value;
      const expenseDate = expense.date;

      if (from && expenseDate < from) return false;
      if (to && expenseDate > to) return false;

      return true;
    }

    function getVisibleExpenses() {
      return expenses.filter(matchesFilters);
    }

    function render() {
      const visible = getVisibleExpenses();

      expenseListEl.innerHTML = '';
      visible.forEach(expense => {
        const tr = document.createElement('tr');
        tr.className = 'expense';
        tr.dataset.id = expense.id;

        const amountTd = document.createElement('td');
        amountTd.className = 'amount';
        amountTd.textContent = formatCurrency(expense.amount);

        const categoryTd = document.createElement('td');
        categoryTd.appendChild(createCategoryBadge(expense.category));

        const dateTd = document.createElement('td');
        dateTd.textContent = expense.date;

        const noteTd = document.createElement('td');
        noteTd.textContent = expense.note || '';

        const deleteTd = document.createElement('td');
        const deleteBtn = document.createElement('button');
        deleteBtn.className = 'exp-del';
        deleteBtn.textContent = 'Delete';
        deleteBtn.addEventListener('click', () => deleteExpense(expense.id));
        deleteTd.appendChild(deleteBtn);

        tr.append(amountTd, categoryTd, dateTd, noteTd, deleteTd);
        expenseListEl.appendChild(tr);
      });

      updateTotals(visible);
    }

    function updateTotals(visibleExpenses) {
      const totals = {};
      CATEGORIES.forEach(cat => totals[cat] = 0);

      let grandTotal = 0;
      visibleExpenses.forEach(expense => {
        totals[expense.category] += expense.amount;
        grandTotal += expense.amount;
      });

      CATEGORIES.forEach(cat => {
        const el = document.querySelector(`.cat-total[data-cat="${cat}"]`);
        if (el) el.textContent = formatCurrency(totals[cat]);
      });

      totalEl.textContent = formatCurrency(grandTotal);
    }

    function addExpense(e) {
      e.preventDefault();
      formErrorEl.textContent = '';

      const amount = parseFloat(amountEl.value);
      const category = categoryEl.value;
      const date = dateEl.value;
      const note = noteEl.value.trim();

      if (isNaN(amount) || amount <= 0) {
        formErrorEl.textContent = 'Please enter a valid positive amount.';
        return;
      }
      if (!date) {
        formErrorEl.textContent = 'Please select a date.';
        return;
      }

      const expense = {
        id: Date.now().toString(),
        amount,
        category,
        date,
        note
      };

      expenses.unshift(expense);
      saveExpenses();
      render();

      amountEl.value = '';
      noteEl.value = '';
      dateEl.value = new Date().toISOString().split('T')[0];
    }

    function deleteExpense(id) {
      expenses = expenses.filter(e => e.id !== id);
      saveExpenses();
      render();
    }

    function init() {
      loadExpenses();
      dateEl.value = new Date().toISOString().split('T')[0];

      document.getElementById('expense-form').addEventListener('submit', addExpense);
      filterCategoryEl.addEventListener('change', render);
      filterFromEl.addEventListener('change', render);
      filterToEl.addEventListener('change', render);

      render();
    }

    init();
  </script>
</body>
</html>
